// Solution
#include <iostream>
#include <vector>
#include <algorithm>

class Solution {
  public:
    vector<int> fib(int n) {
      if (n <= 0) return vector<int>();
      vector<int> fibSequence = {0, 1};
      for (int i = 2; i < n; i++) fibSequence.push_back(fibSequence[i-1] + fibSequence[i-2]);
      return fibSequence;
    }
};

int main() {
  int n; std::cin >> n;
  Solution solution;
  std::vector<int> result = solution.fib(n);
  for (int num : result) std::cout << num << ' ';
  std::cout << std::endl;
  return 0;
}

