// Solution
from typing import List
import sys

class Solution:
    def fib(self, n: int) -> List[int]:
        if n <= 0:
            return []
        fibSequence = [0, 1]
        for i in range(2, n):
            fibSequence.append(fibSequence[i-1] + fibSequence[i-2])
        return fibSequence

if __name__ == '__main__':
    n = int(input())
    solution = Solution()
    result = solution.fib(n)
    print(' '.join(map(str, result)))

